// BST operations
class BinarySearchTree {
public:
    BinarySearchTree() : root(nullptr) {}

    void insert(string word, string definition) {
        root = insertNode(root, word, definition);
    }

    Node* insertNode(Node* node, string word, string definition) {
        if (node == nullptr) {
            return new Node(word, definition);
        }

        if (word < node->word) {
            node->right = insertNode(node->right, word, definition);
        } else {
            node->left = insertNode(node->left, word, definition);
        }

        return node;
    }

    bool search(string word) {
        return searchNode(root, word);
    }

    bool searchNode(Node* node, string word) {
        if (node == nullptr) return false;
        if (node->word == word) return true;
        return searchNode(node->left, word) || searchNode(node->right, word);
    }

    void deleteNode(string word) {
        root = deleteNodeRecursive(root, word);
    }

    Node* deleteNodeRecursive(Node* node, string word) {
        if (node == nullptr) return node;

        if (word < node->word) {
            node->left = deleteNodeRecursive(node->left, word);
        } else if (word > node->word) {
            node->right = deleteNodeRecursive(node->right, word);
        } else {
            // Node found, delete
            if (node->left == nullptr) {
                return node->right;
            } else if (node->right == nullptr) {
                return node->left;
            } else {
                // Node has two children: find the inorder successor
                Node* successor = getInorderSuccessor(node->right);
                node->word = successor->word;
                node->definition = successor->definition;

                node->right = deleteNodeRecursive(node->right, successor->word);
            }
        }

        return node;
    }

    Node* getInorderSuccessor(Node* node) {
        Node* successor = node->right;
        while (successor->left != nullptr) {
            successor = successor->left;
        }
        return successor;
    }

    void printAll() {
        printInorder(root);
    }

    void printInorder(Node* node) {
        if (node != nullptr) {
            printInorder(node->left);
            cout << node->word << " : " << node->definition << endl;
            printInorder(node->right);
        }
    }
};

